  ('dietitian-moex-04275', 'dietitian', 'dietitian-moex-113-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '若不吃蔬菜者得到癌症的風險為1.00，每週吃蔬菜小於1次者風險0.91，每週1～2次者風險0.91，每週3～4 次風險0.83，每週≧ 5次者的風險0.76，且p for trend = 0.001。下列敘述何者正確？', '["比起每週吃1～2次蔬菜者，每週吃3～4次蔬菜者，有顯著較低的癌症發生風險", "比起每週吃1～2次蔬菜者，每週吃5次以上蔬菜者，有顯著較低的癌症發生風險", "比起每週吃3～4次蔬菜者，每週吃5次以上蔬菜者，有顯著較低的癌症發生風險", "吃蔬菜頻率越高者，有顯著較低的癌症發生風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:34+00:00", "source_pdf_sha1": "cfe2ad5d83fc", "answer_pdf_sha1": "e5ac6dfb7c17", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
